public class SimpleDoWhileLoop {
  public static void main(String[] args) {
    int counter = 1;
    do {
      System.out.println("Təkrar: " + counter);
      counter++;
    } while (counter <= 5);
  }
}
// Çıxış:
// Təkrar: 1
// Təkrar: 2
// Təkrar: 3
// Təkrar: 4
// Təkrar: 5

public class DoWhileVsWhile {
  public static void main(String[] args) {
    int counter = 6;
    // While dövrü
    System.out.println("While dövrü:");
    while (counter <= 5) {
      System.out.println("Təkrar: " + counter);
      counter++;
    }
    // Do-While dövrü
    System.out.println("Do-While dövrü:");
    do {
      System.out.println("Təkrar: " + counter);
      counter++;
    } while (counter <= 5);
  }
}
// Çıxış:
// While dövrü:
// (heç bir çıxış, çünki şərt əvvəldən yanlışdır)
// Do-While dövrü:
// Təkrar: 6

public class NestedDoWhileLoop {
  public static void main(String[] args) {
    int i = 1;
    do {
      int j = 1;
      do {
        System.out.println("i: " + i + ", j: " + j);
        j++;
      } while (j <= 3);
      i++;
    } while (i <= 3);
  }
}
// Çıxış:
// i: 1, j: 1
// i: 1, j: 2
// i: 1, j: 3
// i: 2, j: 1
// i: 2, j: 2
// i: 2, j: 3
// i: 3, j: 1
// i: 3, j: 2
// i: 3, j: 3

public class BreakContinueDoWhile {
  public static void main(String[] args) {
    int counter = 1;
    do {
      if (counter == 3) {
        counter++;
        continue; // 3-ü buraxır
      }
      if (counter == 5) {
        break; // Dövrü dayandırır
      }
      System.out.println("Dəyər: " + counter);
      counter++;
    } while (counter <= 5);
  }
}
// Çıxış:
// Dəyər: 1
// Dəyər: 2
// Dəyər: 4

public class BalanceCheck {
  public static void main(String[] args) {
    double balance = 50.0;
    double costPerItem = 15.0;
    int itemsBought = 0;
    do {
      if (balance >= costPerItem) {
        balance -= costPerItem;
        itemsBought++;
        System.out.println("Alınan məhsul: " + itemsBought + ", Qalan balans: " + balance);
      } else {
        System.out.println("Kifayət qədər balans yoxdur!");
        break;
      }
    } while (balance > 0);
  }
}
// Çıxış:
// Alınan məhsul: 1, Qalan balans: 35.0
// Alınan məhsul: 2, Qalan balans: 20.0
// Alınan məhsul: 3, Qalan balans: 5.0
// Kifayət qədər balans yoxdur!

