public class BreakContinueDoWhile {
  public static void main(String[] args) {
    int counter = 1;
    do {
      if (counter == 3) {
        counter++;
        continue; // Skips 3
      }
      if (counter == 5) {
        break; // Stops the loop
      }
      System.out.println("Value: " + counter);
      counter++;
    } while (counter <= 5);
  }
}
// Output:
// Value: 1
// Value: 2
// Value: 4

public class BalanceCheck {
  public static void main(String[] args) {
    double balance = 50.0;
    double costPerItem = 15.0;
    int itemsBought = 0;
    do {
      if (balance >= costPerItem) {
        balance -= costPerItem;
        itemsBought++;
        System.out.println("Items bought: " + itemsBought + ", Remaining balance: " + balance);
      } else {
        System.out.println("Insufficient balance!");
        break;
      }
    } while (balance > 0);
  }
}
// Output:
// Items bought: 1, Remaining balance: 35.0
// Items bought: 2, Remaining balance: 20.0
// Items bought: 3, Remaining balance: 5.0
// Insufficient balance!

